class MagicDictionary {
    unordered_set<string> st;
public:
    void buildDict(vector<string> w){ st={w.begin(),w.end()}; }
    bool search(string word){
        for(int i=0;i<(int)word.size();i++)
            for(char c='a';c<='z';c++){
                if(c==word[i]) continue;
                string t=word; t[i]=c;
                if(st.count(t)) return true;
            }
        return false;
    }
};

